import React, { useEffect, useState } from "react";
import axios from "axios";

const Dashboard = () => {
  const [todos, setTodos] = useState([]);
  const [title, setTitle] = useState("");
  const [editId, setEditId] = useState(null);

  const userId = localStorage.getItem("userId");

  // ✅ Fetch Todos
  const fetchTodos = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5001/api/todos?userId=${userId}`
      );
      setTodos(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchTodos();
  }, []);

  // ➕ Add / Update Todo
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (editId) {
        await axios.put(
          `http://localhost:5001/api/todos/${editId}`,
          { title }
        );
        setEditId(null);
      } else {
        await axios.post("http://localhost:5001/api/todos", {
          userId,
          title
        });
      }

      setTitle("");
      fetchTodos();

    } catch (err) {
      console.log(err);
    }
  };

  // ❌ Delete
  const handleDelete = async (id) => {
    await axios.delete(`http://localhost:5001/api/todos/${id}`);
    fetchTodos();
  };

  // ✅ Toggle
  const handleToggle = async (id) => {
    await axios.put(
      `http://localhost:5001/api/todos/toggle/${id}`
    );
    fetchTodos();
  };

  // ✏️ Edit
  const handleEdit = (todo) => {
    setTitle(todo.title);
    setEditId(todo._id);
  };

  // 🚪 Logout
  const handleLogout = () => {
    localStorage.removeItem("userId");
    window.location.href = "/";
  };

  return (
    <div className="min-h-screen bg-[rgb(35,46,88)] flex justify-center items-start pt-10">

      <div className="w-full max-w-2xl backdrop-blur-lg bg-white/10 border border-white/20 rounded-2xl p-6 text-white shadow-xl">

        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold">Todo Dashboard</h2>
          <button
            onClick={handleLogout}
            className="bg-red-500 px-3 py-1 rounded"
          >
            Logout
          </button>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="flex gap-3 mb-6">
          <input
            type="text"
            placeholder="Enter task..."
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="flex-1 px-4 py-2 rounded-lg bg-white/20 border border-white/30 focus:outline-none"
          />
          <button className="bg-white text-[rgb(35,46,88)] px-4 py-2 rounded-lg font-semibold">
            {editId ? "Update" : "Add"}
          </button>
        </form>

        {/* Todo List */}
        <div className="space-y-3">
          {todos.map((todo) => (
            <div
              key={todo._id}
              className="flex justify-between items-center bg-white/20 p-3 rounded-lg"
            >
              <span
                onClick={() => handleToggle(todo._id)}
                className={`cursor-pointer ${
                  todo.completed ? "line-through text-gray-300" : ""
                }`}
              >
                {todo.title}
              </span>

              <div className="flex gap-2">
                <button
                  onClick={() => handleEdit(todo)}
                  className="bg-yellow-400 px-2 py-1 rounded text-black"
                >
                  Edit
                </button>

                <button
                  onClick={() => handleDelete(todo._id)}
                  className="bg-red-500 px-2 py-1 rounded"
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

export default Dashboard;
